+    #[test]
+    fn diagnostic_entry_checksum_deterministic() {
+        let entry1 = DiagnosticEntry::new(DiagnosticEventKind::ModeChanged)
+            .with_previous_mode(InspectorMode::Off)
+            .with_mode(InspectorMode::Full)
+            .with_flag("hits", true)
