+            .with_checksum();
+        let entry2 = DiagnosticEntry::new(DiagnosticEventKind::ModeChanged)
+            .with_previous_mode(InspectorMode::Off)
+            .with_mode(InspectorMode::Full)
+            .with_flag("hits", true)
+            .with_context("test")
+            .with_checksum();
+        assert_eq!(entry1.checksum, entry2.checksum);
+        assert_ne!(entry1.checksum, 0);
+    }
